import{_ as a,o as n,c as s,a3 as i}from"./chunks/framework.CjquFG0V.js";const w=JSON.parse('{"title":"36. Vehicle Allowance","description":"","frontmatter":{"title":"36. Vehicle Allowance","eba":"Nurses and Midwives 2024-2028","topics":["allowances"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/36-vehicle-allowance.md","filePath":"ebas/nurses-midwives/allowances/36-vehicle-allowance.md"}'),l={name:"ebas/nurses-midwives/allowances/36-vehicle-allowance.md"};function c(o,e,t,r,d,h){return n(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_36-vehicle-allowance" tabindex="-1">36. Vehicle Allowance <a class="header-anchor" href="#_36-vehicle-allowance" aria-label="Permalink to &quot;36. Vehicle Allowance&quot;">​</a></h1><p><strong>36.1</strong> Employees required to use their own car, motorcycle or bicycle in connection with their duties will be paid the applicable vehicle allowance as set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>. The minimum payment for each occasion of use is set out in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>.</p><p><strong>36.2</strong> In <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Cylinder refers to the number of cylinders in a vehicle&#39;s engine, and Electric car refers to a vehicle which has an electric motor instead of an internal combustion engine.</p>',3)])])}const m=a(l,[["render",c]]);export{w as __pageData,m as default};
